'use client';

import Link from 'next/link';
import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { Scale, LogOut, User, ShieldCheck, Users, Home, LayoutDashboard } from 'lucide-react';
import { supabase } from '@/lib/supabase';

export default function Navbar() {
    const [user, setUser] = useState<any>(null);
    const router = useRouter();

    useEffect(() => {
        // Check current session
        const checkUser = async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (session?.user) {
                setUser({
                    email: session.user.email,
                    role: session.user.user_metadata.role || 'public'
                });
            }
        };

        checkUser();

        // Listen for auth changes
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            if (session?.user) {
                setUser({
                    email: session.user.email,
                    role: session.user.user_metadata.role || 'public'
                });
            } else {
                setUser(null);
            }
        });

        return () => subscription.unsubscribe();
    }, []);

    const logout = async () => {
        await supabase.auth.signOut();
        setUser(null);
        router.push('/');
    };

    return (
        <nav className="bg-white shadow z-50 sticky top-0 border-b border-indigo-100">
            <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                <div className="flex justify-between h-16">
                    <Link href="/" className="flex items-center space-x-3">
                        <div className="relative h-10 w-10 overflow-hidden">
                            <img src="/logo.png" alt="Logo" className="object-contain h-full w-full" />
                        </div>
                        <div>
                            <h1 className="text-xl font-bold text-indigo-900 tracking-tight">
                                GOVT.LEGAL<span className="text-indigo-600">.AI</span>
                            </h1>
                            <p className="text-[10px] text-gray-500 font-bold tracking-[0.2em] uppercase">
                                Kalasalingam Academy
                            </p>
                        </div>
                    </Link>

                    <div className="flex items-center space-x-8">
                        <Link href="/" className="text-gray-600 hover:text-indigo-600 font-semibold text-sm flex items-center gap-2 transition-colors">
                            <Home className="h-4 w-4" /> Home
                        </Link>
                        <Link
                            href={user ? "/dashboard" : "/auth/login"}
                            className="text-gray-600 hover:text-indigo-600 font-semibold text-sm flex items-center gap-2 transition-colors"
                        >
                            <LayoutDashboard className="h-4 w-4" /> Dashboard
                        </Link>
                        <Link href="/team" className="text-gray-600 hover:text-indigo-600 font-semibold text-sm flex items-center gap-2 transition-colors">
                            <Users className="h-4 w-4" /> Team
                        </Link>

                        {user ? (
                            <div className="flex items-center space-x-4 ml-4 pl-4 border-l border-gray-200">
                                <div className="flex items-center space-x-2">
                                    <div className="h-8 w-8 bg-indigo-100 rounded-full flex items-center justify-center">
                                        <User className="h-4 w-4 text-indigo-600" />
                                    </div>
                                    <div className="hidden md:block">
                                        <p className="text-xs font-bold text-gray-900 leading-none">{user.email.split('@')[0]}</p>
                                        <p className="text-[10px] text-gray-500 uppercase">{user.role}</p>
                                    </div>
                                </div>
                                <button
                                    onClick={logout}
                                    className="p-2 text-gray-400 hover:text-red-500 transition-colors"
                                    title="Logout"
                                >
                                    <LogOut className="h-5 w-5" />
                                </button>
                            </div>
                        ) : (
                            <div className="flex items-center space-x-3">
                                <Link
                                    href="/auth/login"
                                    className="text-indigo-600 hover:text-indigo-700 font-bold text-sm px-4 py-2"
                                >
                                    Login
                                </Link>
                                <Link
                                    href="/auth/register"
                                    className="bg-indigo-600 text-white px-5 py-2 rounded-lg font-bold text-sm hover:bg-indigo-700 transition shadow-sm hover:shadow-md"
                                >
                                    Join System
                                </Link>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </nav>
    );
}
